-- =============================================================================
-- IntegratedAccSys - PostgreSQL Schema (Converted from SQL Server)
-- Generated: 2026-06-08
-- Source: Database/IntegratedAccSys_Full.sql (SQL Server 2019)
-- Target: PostgreSQL 17
-- =============================================================================
-- Conversion notes (T-SQL -> PL/pgSQL):
--   * IDENTITY(1,1)         -> GENERATED BY DEFAULT AS IDENTITY
--   * NVARCHAR(n)           -> VARCHAR(n)   (UTF-8 encoded DB)
--   * VARBINARY(MAX)        -> BYTEA
--   * NVARCHAR(MAX)         -> TEXT
--   * DATETIME              -> TIMESTAMP
--   * BIT                   -> BOOLEAN
--   * GETDATE()             -> CURRENT_TIMESTAMP
--   * NEWID()               -> gen_random_uuid()
--   * UNIQUEIDENTIFIER      -> UUID
--   * [dbo].                -> public.
--   * CREATE OR ALTER PROC  -> CREATE OR REPLACE PROCEDURE / FUNCTION
--   * SET NOCOUNT ON        -> removed (PostgreSQL behavior)
--   * IF EXISTS (...) DROP  -> DROP ... IF EXISTS
--   * DATEDIFF              -> EXTRACT(EPOCH FROM ...)/86400 or age()
--   * ISNULL(a,b)           -> COALESCE(a,b)
-- =============================================================================

-- Make sure pgcrypto is available for gen_random_uuid()
CREATE EXTENSION IF NOT EXISTS "pgcrypto";

DROP SCHEMA IF EXISTS public CASCADE;

CREATE SCHEMA public;

-- =============================================================================
-- SECTION 2: SECURITY DOMAIN TABLES
-- =============================================================================

CREATE TABLE public.tblWindows (
    WindowID INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    WindowCode VARCHAR(50) UNIQUE NOT NULL,
    WindowNameAr VARCHAR(200) NOT NULL,
    WindowNameEn VARCHAR(200),
    ModuleName VARCHAR(100) NOT NULL,
    FormName VARCHAR(200),
    IsActive BOOLEAN DEFAULT TRUE,
    SortOrder INT DEFAULT 0,
    IconName VARCHAR(100),
    ParentWindowID INT,
    CreatedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    ModifiedAt TIMESTAMP,
    Notes TEXT,
    CONSTRAINT FK_tblWindows_Parent FOREIGN KEY (ParentWindowID) REFERENCES public.tblWindows (WindowID)
);

CREATE INDEX idx_tblWindows_Module ON public.tblWindows (ModuleName);

CREATE INDEX idx_tblWindows_Parent ON public.tblWindows (ParentWindowID);

CREATE TABLE public.tblUsers (
    UserCode INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    UserID VARCHAR(15) UNIQUE NOT NULL,
    UserPassword BYTEA NOT NULL,
    Salt BYTEA NOT NULL,
    UserNameAr VARCHAR(200),
    UserNameEn VARCHAR(200),
    Email VARCHAR(100),
    Phone VARCHAR(50),
    Mobile VARCHAR(50),
    IsActive BOOLEAN DEFAULT TRUE,
    IsAdmin BOOLEAN DEFAULT FALSE,
    PasswordLastChanged TIMESTAMP,
    PasswordHistory1 BYTEA,
    PasswordHistory2 BYTEA,
    LastLoginAt TIMESTAMP,
    LoginAttempts INT DEFAULT 0,
    LockedUntil TIMESTAMP,
    MustChangePassword BOOLEAN DEFAULT FALSE,
    BranchCode INT,
    Department VARCHAR(100),
    JobTitle VARCHAR(100),
    Photo BYTEA,
    IsOnline BOOLEAN DEFAULT FALSE,
    CreatedBy INT,
    CreatedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    ModifiedBy INT,
    ModifiedAt TIMESTAMP,
    Notes TEXT
);

CREATE INDEX idx_tblUsers_UserID ON public.tblUsers (UserID);

CREATE INDEX idx_tblUsers_IsActive ON public.tblUsers (IsActive);

CREATE INDEX idx_tblUsers_Branch ON public.tblUsers (BranchCode);

CREATE TABLE public.tblUserRoles (
    RoleID INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    RoleName VARCHAR(50) NOT NULL UNIQUE,
    RoleNameAr VARCHAR(100) NOT NULL,
    RoleNameEn VARCHAR(100),
    Description VARCHAR(500),
    IsActive BOOLEAN DEFAULT TRUE,
    CreatedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    Notes TEXT
);

CREATE TABLE public.tblUserRoleAssignments (
    AssignmentID INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    UserCode INT NOT NULL,
    RoleID INT NOT NULL,
    AssignedBy INT,
    AssignedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    ExpiresAt TIMESTAMP,
    IsActive BOOLEAN DEFAULT TRUE,
    CONSTRAINT FK_UserRole_User FOREIGN KEY (UserCode) REFERENCES public.tblUsers (UserCode),
    CONSTRAINT FK_UserRole_Role FOREIGN KEY (RoleID) REFERENCES public.tblUserRoles (RoleID),
    CONSTRAINT UQ_UserRole_Assignment UNIQUE (UserCode, RoleID)
);

CREATE TABLE public.tblPrivileges (
    PrivilegeID INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    UserCode INT NOT NULL,
    WindowID INT NOT NULL,
    CanDisplay BOOLEAN DEFAULT TRUE,
    CanAdd BOOLEAN DEFAULT TRUE,
    CanEdit BOOLEAN DEFAULT TRUE,
    CanDelete BOOLEAN DEFAULT TRUE,
    CanPrint BOOLEAN DEFAULT FALSE,
    CanExport BOOLEAN DEFAULT FALSE,
    CanApprove BOOLEAN DEFAULT FALSE,
    CanPost BOOLEAN DEFAULT FALSE,
    CustomPermissions TEXT,
    EffectiveFrom TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    EffectiveTo TIMESTAMP,
    CreatedBy INT,
    CreatedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    ModifiedBy INT,
    ModifiedAt TIMESTAMP,
    CONSTRAINT FK_Privileges_User FOREIGN KEY (UserCode) REFERENCES public.tblUsers (UserCode),
    CONSTRAINT FK_Privileges_Window FOREIGN KEY (WindowID) REFERENCES public.tblWindows (WindowID),
    CONSTRAINT UQ_UserWindow UNIQUE (UserCode, WindowID)
);

CREATE INDEX idx_Privileges_User ON public.tblPrivileges (UserCode);

CREATE INDEX idx_Privileges_Window ON public.tblPrivileges (WindowID);

CREATE TABLE public.tblSessions (
    SessionID INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    SessionToken UUID NOT NULL UNIQUE DEFAULT gen_random_uuid (),
    UserCode INT NOT NULL,
    UserID VARCHAR(15) NOT NULL,
    BranchCode INT,
    MachineName VARCHAR(100),
    IPAddress VARCHAR(50),
    MacAddress VARCHAR(50),
    BrowserInfo VARCHAR(500),
    CreatedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    LastActivityAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    ExpiresAt TIMESTAMP,
    LogoutAt TIMESTAMP,
    IsActive BOOLEAN DEFAULT TRUE,
    SessionData TEXT,
    CONSTRAINT FK_Sessions_User FOREIGN KEY (UserCode) REFERENCES public.tblUsers (UserCode)
);

CREATE INDEX idx_Sessions_Token ON public.tblSessions (SessionToken);

CREATE INDEX idx_Sessions_User ON public.tblSessions (UserCode);

CREATE INDEX idx_Sessions_Expires ON public.tblSessions (ExpiresAt);

CREATE TABLE public.tblAuditLogs (
    AuditID BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    UserCode INT,
    UserID VARCHAR(15),
    EventType VARCHAR(50) NOT NULL,
    EventCategory VARCHAR(50) NOT NULL,
    EventDescription VARCHAR(1000) NOT NULL,
    TableName VARCHAR(100),
    RecordID INT,
    OldValues TEXT,
    NewValues TEXT,
    SQLCommand TEXT
);
