    CONSTRAINT FK_Products_Category FOREIGN KEY (CategoryCode) REFERENCES public.tblCategories (CategoryCode),
    CONSTRAINT FK_Products_Unit FOREIGN KEY (DefaultUnitCode) REFERENCES public.tblUnits (UnitCode)
