    CONSTRAINT FK_StoreProducts_Store FOREIGN KEY (StoreCode) REFERENCES public.tblStores (StoreCode),
    CONSTRAINT FK_StoreProducts_Product FOREIGN KEY (ProductCode) REFERENCES public.tblProducts (ProductCode),
    CONSTRAINT FK_StoreProducts_Batch FOREIGN KEY (BatchID) REFERENCES public.tblProductBatches (BatchID),
    CONSTRAINT UQ_StoreProduct_Batch UNIQUE (
        StoreCode,
        ProductCode,
        BatchID
    )
);

