    CONSTRAINT FK_Pricing_PriceList FOREIGN KEY (PriceListCode) REFERENCES public.tblPriceLists (PriceListCode),
    CONSTRAINT FK_Pricing_Unit FOREIGN KEY (UnitCode) REFERENCES public.tblUnits (UnitCode)
);

