CREATE TABLE public.tblCustomers (
    CustomerCode INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    CustomerID VARCHAR(15) UNIQUE NOT NULL,
    CustomerNameAr VARCHAR(200) NOT NULL,
    CustomerNameEn VARCHAR(200),
    CustomerType VARCHAR(50) DEFAULT 'INDIVIDUAL',
    TaxNumber VARCHAR(50),
    VATNumber VARCHAR(50),
    Address VARCHAR(500),
    City VARCHAR(100),
    Country VARCHAR(100) DEFAULT 'SA',
    Phone VARCHAR(50),
    Mobile VARCHAR(50),
    Email VARCHAR(100),
    BranchCode INT,
    PriceListCode INT,
    PaymentTermCode INT,
    CreditLimit NUMERIC(18, 4) DEFAULT 0,
    CurrentCredit NUMERIC(18, 4) DEFAULT 0,
    AvailableCredit NUMERIC(18, 4) GENERATED ALWAYS AS (CreditLimit - CurrentCredit) STORED,
    PaymentDays INT DEFAULT 0,
    Balance NUMERIC(18, 4) DEFAULT 0,
    TotalSales NUMERIC(18, 4) DEFAULT 0,
    LastSaleDate DATE,
    CustomerSince DATE,
    IsActive BOOLEAN DEFAULT TRUE,
    IsBlocked BOOLEAN DEFAULT FALSE,
    Notes TEXT,
    CONSTRAINT FK_Customers_Branch FOREIGN KEY (BranchCode) REFERENCES public.tblBranches (BranchCode),
    CONSTRAINT FK_Customers_PriceList FOREIGN KEY (PriceListCode) REFERENCES public.tblPriceLists (PriceListCode),
    CONSTRAINT FK_Customers_PaymentTerm FOREIGN KEY (PaymentTermCode) REFERENCES public.tblPaymentTerms (PaymentTermCode)
);

CREATE TABLE public.tblCustomerContacts (
    ContactID INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    CustomerCode INT NOT NULL,
    ContactName VARCHAR(200),
    JobTitle VARCHAR(100),
    Phone VARCHAR(50),
    Mobile VARCHAR(50),
    Email VARCHAR(100),
    IsPrimary BOOLEAN DEFAULT FALSE,
    CONSTRAINT FK_CustomerContacts_Customer FOREIGN KEY (CustomerCode) REFERENCES public.tblCustomers (CustomerCode) ON DELETE CASCADE
);

CREATE TABLE public.tblSuppliers (
    SupplierCode INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    SupplierID VARCHAR(15) UNIQUE NOT NULL,
    SupplierNameAr VARCHAR(200) NOT NULL,
    SupplierNameEn VARCHAR(200),
    SupplierType VARCHAR(50) DEFAULT 'INDIVIDUAL',
    TaxNumber VARCHAR(50),
    VATNumber VARCHAR(50),
    Address VARCHAR(500),
    City VARCHAR(100),
    Country VARCHAR(100) DEFAULT 'SA',
    Phone VARCHAR(50),
    Mobile VARCHAR(50),
    Email VARCHAR(100),
    BranchCode INT,
    PaymentTermCode INT,
    BankName VARCHAR(200),
    AccountNumber VARCHAR(50),
    IBAN VARCHAR(50),
    SwiftCode VARCHAR(20),
    CreditLimit NUMERIC(18, 4) DEFAULT 0,
    CurrentCredit NUMERIC(18, 4) DEFAULT 0,
    AvailableCredit NUMERIC(18, 4) GENERATED ALWAYS AS (CreditLimit - CurrentCredit) STORED,
    PaymentDays INT DEFAULT 0,
    Balance NUMERIC(18, 4) DEFAULT 0,
    TotalPurchases NUMERIC(18, 4) DEFAULT 0,
    LastPurchaseDate DATE,
    SupplierSince DATE,
    IsActive BOOLEAN DEFAULT TRUE,
    IsBlocked BOOLEAN DEFAULT FALSE,
    Notes TEXT,
    CONSTRAINT FK_Suppliers_Branch FOREIGN KEY (BranchCode) REFERENCES public.tblBranches (BranchCode),
    CONSTRAINT FK_Suppliers_PaymentTerm FOREIGN KEY (PaymentTermCode) REFERENCES public.tblPaymentTerms (PaymentTermCode)
);

CREATE TABLE public.tblSupplierContacts (
    ContactID INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    SupplierCode INT NOT NULL,
    ContactName VARCHAR(200),
    JobTitle VARCHAR(100),
    Phone VARCHAR(50),
    Mobile VARCHAR(50),
    Email VARCHAR(100),
    IsPrimary BOOLEAN DEFAULT FALSE,
    CONSTRAINT FK_SupplierContacts_Supplier FOREIGN KEY (SupplierCode) REFERENCES public.tblSuppliers (SupplierCode) ON DELETE CASCADE
);

-- Operations (Sales / Purchases / Returns)
CREATE TABLE public.tblOperationHeader (
    OperationCode BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    OperationID VARCHAR(30) UNIQUE NOT NULL,
    OperationType VARCHAR(20) NOT NULL, -- SALE / PURCHASE / SALE_RETURN / PURCHASE_RETURN
    OperationDate DATE NOT NULL,
    FiscalYear INT NOT NULL,
    FiscalPeriod INT NOT NULL,
    CustomerCode INT,
    SupplierCode INT,
    BranchCode INT,
    StoreCode INT,
    CurrencyCode INT,
    ExchangeRate NUMERIC(18, 8) DEFAULT 1.0,
    SubTotal NUMERIC(18, 4) DEFAULT 0,
    DiscountPercent NUMERIC(8, 3) DEFAULT 0,
    DiscountAmount NUMERIC(18, 4) DEFAULT 0,
    TaxAmount NUMERIC(18, 4) DEFAULT 0,
    AdditionalCharges NUMERIC(18, 4) DEFAULT 0,
    Total NUMERIC(18, 4) DEFAULT 0,
    PaidAmount NUMERIC(18, 4) DEFAULT 0,
    RemainingAmount NUMERIC(18, 4) DEFAULT 0,
    PaymentMethodCode INT,
    ReferenceNo VARCHAR(100),
    Description VARCHAR(500),
    IsPosted BOOLEAN DEFAULT FALSE,
    PostedAt TIMESTAMP,
    PostedBy INT,
    IsCancelled BOOLEAN DEFAULT FALSE,
    CreatedBy INT,
    CreatedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    Notes TEXT,
    CONSTRAINT FK_OpHeader_Customer FOREIGN KEY (CustomerCode) REFERENCES public.tblCustomers (CustomerCode),
    CONSTRAINT FK_OpHeader_Supplier FOREIGN KEY (SupplierCode) REFERENCES public.tblSuppliers (SupplierCode),
    CONSTRAINT FK_OpHeader_Branch FOREIGN KEY (BranchCode) REFERENCES public.tblBranches (BranchCode),
    CONSTRAINT FK_OpHeader_Store FOREIGN KEY (StoreCode) REFERENCES public.tblStores (StoreCode),
    CONSTRAINT FK_OpHeader_Currency FOREIGN KEY (CurrencyCode) REFERENCES public.tblCurrencies (CurrencyCode),
    CONSTRAINT FK_OpHeader_PaymentMethod FOREIGN KEY (PaymentMethodCode) REFERENCES public.tblPaymentMethods (PaymentMethodCode)
);

CREATE TABLE public.tblOperationBody (
    OperationDetailID BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    OperationCode BIGINT NOT NULL,
    LineNumber INT NOT NULL,
    ProductCode INT NOT NULL,
    UnitCode INT,
    BatchID INT,
    Quantity NUMERIC(18, 4) DEFAULT 0,
    UnitPrice NUMERIC(18, 4) DEFAULT 0,
    Cost NUMERIC(18, 4) DEFAULT 0,
    DiscountPercent NUMERIC(8, 3) DEFAULT 0,
    DiscountAmount NUMERIC(18, 4) DEFAULT 0,
    TaxPercent NUMERIC(8, 3) DEFAULT 0,
    TaxAmount NUMERIC(18, 4) DEFAULT 0,
    Total NUMERIC(18, 4) DEFAULT 0,
    StoreCode INT,
    Description VARCHAR(500),
    CONSTRAINT FK_OpBody_Header FOREIGN KEY (OperationCode) REFERENCES public.tblOperationHeader (OperationCode) ON DELETE CASCADE,
    CONSTRAINT FK_OpBody_Product FOREIGN KEY (ProductCode) REFERENCES public.tblProducts (ProductCode),
    CONSTRAINT FK_OpBody_Unit FOREIGN KEY (UnitCode) REFERENCES public.tblUnits (UnitCode),
    CONSTRAINT FK_OpBody_Batch FOREIGN KEY (BatchID) REFERENCES public.tblProductBatches (BatchID)
);

CREATE TABLE public.tblOperationTaxes (
    OperationTaxID BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    OperationCode BIGINT NOT NULL,
    TaxType VARCHAR(50),
    TaxPercent NUMERIC(8, 3) DEFAULT 0,
    TaxAmount NUMERIC(18, 4) DEFAULT 0,
    CONSTRAINT FK_OpTaxes_Header FOREIGN KEY (OperationCode) REFERENCES public.tblOperationHeader (OperationCode) ON DELETE CASCADE
);

CREATE TABLE public.tblProductMovement (
    MovementID BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    ProductCode INT NOT NULL,
    StoreCode INT NOT NULL,
    MovementType VARCHAR(20) NOT NULL, -- IN / OUT / TRANSFER / ADJUST
    MovementDate TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    Quantity NUMERIC(18, 4) NOT NULL,
    UnitCost NUMERIC(18, 4) DEFAULT 0,
    ReferenceType VARCHAR(50), -- SALE / PURCHASE / ADJUST
    ReferenceCode BIGINT,
    BatchID INT,
    Notes TEXT,
    CONSTRAINT FK_Movement_Product FOREIGN KEY (ProductCode) REFERENCES public.tblProducts (ProductCode),
    CONSTRAINT FK_Movement_Store FOREIGN KEY (StoreCode) REFERENCES public.tblStores (StoreCode)
);

-- =============================================================================
-- END OF TABLES
